local uri = ngx.var.uri
local args = ngx.req.get_uri_args()  -- this is not a list of params, it's a map! { <param> = <value> }
local filename = args["file"] or "index"  -- default file name if nothing was given in URI arguments. I.e., http://example.com/files/
filename = (filename:sub(-1) == "/") and ("index") or filename   -- add 'index' to filename argument if there is a slash in the end of it. This is for serving default file like index.html. Also it's not really nice, so let's do some refactoring here.
local file = io.open("./files/"..filename, "r")  -- read content from file.
if file then
    ngx.say(file:read("*a"))                 -- send file to client (nginx.say())
